import React, { useState, useEffect } from 'react';
import { ArrowUp } from 'lucide-react';

const ScrollToTop: React.FC = () => {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const toggleVisibility = () => {
      if (window.scrollY > 300) {
        setIsVisible(true);
      } else {
        setIsVisible(false);
      }
    };

    window.addEventListener('scroll', toggleVisibility);
    return () => window.removeEventListener('scroll', toggleVisibility);
  }, []);

  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: 'smooth',
    });
  };

  return (
    <button
      onClick={scrollToTop}
      className={`fixed bottom-8 right-8 z-50 p-3 rounded-full bg-brand-600 text-white shadow-lg transition-all duration-300 transform hover:bg-brand-700 hover:-translate-y-1 hover:shadow-xl focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-500 ${
        isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0 pointer-events-none'
      }`}
      aria-label="Scroll to top"
    >
      <ArrowUp className="w-6 h-6" />
    </button>
  );
};

export default ScrollToTop;

import React from 'react';

interface BaseProps {
  variant?: 'primary' | 'secondary' | 'outline';
  children: React.ReactNode;
  className?: string;
  href?: string;
}

type ButtonProps = BaseProps & React.ButtonHTMLAttributes<HTMLButtonElement>;
type AnchorProps = BaseProps & React.AnchorHTMLAttributes<HTMLAnchorElement>;

const Button: React.FC<ButtonProps | AnchorProps> = ({ variant = 'primary', children, className = '', href, ...props }) => {

  // Changed flex to inline-flex to work correctly for anchor tags
  const baseStyles = "relative px-8 py-4 rounded-full font-bold text-sm tracking-wide transition-all duration-300 overflow-hidden group inline-flex items-center justify-center gap-2 active:scale-95 cursor-pointer";

  const variants = {
    // Primary: Royal Blue, clean and professional
    primary: `
      bg-brand-700 text-white border border-transparent
      shadow-[0_4px_12px_rgba(29,78,216,0.25)]
      hover:shadow-[0_8px_24px_rgba(29,78,216,0.35)]
      hover:-translate-y-0.5
    `,
    // Secondary: Very light gray/white for subtle actions
    secondary: `
      bg-slate-50 text-slate-900 border border-slate-200
      hover:bg-white hover:border-slate-300
      hover:shadow-md hover:-translate-y-0.5
    `,
    // Outline: Clean borders
    outline: `
      bg-transparent border border-slate-300 text-slate-600
      hover:border-slate-900 hover:text-slate-900
    `
  };

  const content = (
    <>
      {/* Animation: Diagonal swipe overlay for Primary */}
      {variant === 'primary' && (
        <div className="absolute inset-0 bg-brand-600 transform scale-x-0 group-hover:scale-x-100 transition-transform origin-left duration-300 ease-out" />
      )}

      {/* Content */}
      <span className="relative z-10 flex items-center justify-center gap-2">
        {children}
      </span>
    </>
  );

  if (href) {
    return (
      <a 
        href={href} 
        className={`${baseStyles} ${variants[variant]} ${className}`}
        {...(props as React.AnchorHTMLAttributes<HTMLAnchorElement>)}
      >
        {content}
      </a>
    );
  }

  return (
    <button
      className={`${baseStyles} ${variants[variant]} ${className}`}
      {...(props as React.ButtonHTMLAttributes<HTMLButtonElement>)}
    >
      {content}
    </button>
  );
};

export default Button;

